from typing import Any, Union, Tuple, Type
def check_types(value: Any, types: Union[Tuple[Type], Type]) -> bool:
    try:
        if isinstance(types, tuple):
            return any([check_types(value, type) for type in types])
        return not not check_type(value, types)
    except:
        raise

class Scope:
